Below is a concise C++ implementation that finds common elements of two arrays without using any extra data structures. It uses in-place sorting and a two-pointer scan. Two versions are provided: (A) returning each common value only once (unique common elements), and (B) returning common elements including duplicates (intersection with multiplicity). Time O(n log n + m log m), extra space O(1) besides input arrays.

#include <bits/stdc++.h>
using namespace std;

// Version A: unique common elements (each value printed once)
void commonUnique(vector<int>& a, vector<int>& b) {
    sort(a.begin(), a.end()); // in-place
    sort(b.begin(), b.end());
    int i = 0, j = 0;
    bool first = true;
    while (i < (int)a.size() && j < (int)b.size()) {
        if (a[i] < b[j]) {
            ++i;
        } else if (a[i] > b[j]) {
            ++j;
        } else {
            // a[i] == b[j], output once and skip duplicates
            if (!first) cout << ' ';
            cout << a[i];
            first = false;
            int val = a[i];
            while (i < (int)a.size() && a[i] == val) ++i;
            while (j < (int)b.size() && b[j] == val) ++j;
        }
    }
    cout << '\n';
}

// Version B: common elements including duplicates (intersection with multiplicity)
void commonWithDuplicates(vector<int>& a, vector<int>& b) {
    sort(a.begin(), a.end()); // in-place
    sort(b.begin(), b.end());
    int i = 0, j = 0;
    bool first = true;
    while (i < (int)a.size() && j < (int)b.size()) {
        if (a[i] < b[j]) {
            ++i;
        } else if (a[i] > b[j]) {
            ++j;
        } else {
            if (!first) cout << ' ';
            cout << a[i];
            first = false;
            ++i;
            ++j;
        }
    }
    cout << '\n';
}

int main() {
    // Example usage:
    vector<int> arr1 = {4, 9, 5, 9, 4};
    vector<int> arr2 = {9, 4, 9, 8};

    // Unique common elements:
    cout << "Unique common elements: ";
    vector<int> a1 = arr1, b1 = arr2;
    commonUnique(a1, b1); // prints: 4 9

    // Common elements including duplicates (intersection):
    cout << "Common with duplicates: ";
    vector<int> a2 = arr1, b2 = arr2;
    commonWithDuplicates(a2, b2); // prints e.g. 4 9 9 (depending on counts and ordering)

    return 0;
}

