#!/usr/bin/env python3
import os
import re
import sys
from collections import Counter

# Usage: python top_words.py [directory]
# If no directory is given, uses current directory.

WORD_RE = re.compile(r"[^\W_']+(?:'[^\W_']+)*", re.UNICODE)  # words including internal apostrophes

def count_words_in_dir(root_dir):
    counter = Counter()
    for dirpath, _, files in os.walk(root_dir):
        for fname in files:
            if not fname.lower().endswith(".txt"):
                continue
            path = os.path.join(dirpath, fname)
            try:
                with open(path, "r", encoding="utf-8", errors="ignore") as f:
                    for line in f:
                        for token in WORD_RE.findall(line):
                            if token.isdigit():
                                continue
                            counter[token.lower()] += 1
            except Exception as e:
                print(f"Warning: could not read {path}: {e}", file=sys.stderr)
    return counter

def main():
    root = sys.argv[1] if len(sys.argv) > 1 else "."
    counts = count_words_in_dir(root)
    for word, cnt in counts.most_common(5):
        print(f"{word}\t{cnt}")

if __name__ == "__main__":
    main()

