#!/usr/bin/env python3

import argparse
import re
from pathlib import Path
from collections import Counter

def count_words_in_directory(directory: str, top_n: int = 5):
    p = Path(directory)
    counter = Counter()
    # match words consisting of letters optionally including internal apostrophes (e.g. don't)
    word_re = re.compile(r"[A-Za-z]+(?:'[A-Za-z]+)?")
    for path in p.rglob('*.txt'):
        try:
            text = path.read_text(encoding='utf-8', errors='ignore')
        except Exception:
            # skip unreadable files
            continue
        words = (w.lower() for w in word_re.findall(text))
        counter.update(words)
    return counter.most_common(top_n)

def main():
    parser = argparse.ArgumentParser(description="Return top-N most frequent words from all .txt files under a directory.")
    parser.add_argument("directory", nargs="?", default=".", help="Directory to scan (default: current directory).")
    parser.add_argument("-n", "--top", type=int, default=5, help="Number of top words to return (default: 5).")
    args = parser.parse_args()

    top_words = count_words_in_directory(args.directory, args.top)
    if not top_words:
        print("No words found in .txt files under", args.directory)
        return

    for word, count in top_words:
        print(f"{word}\t{count}")

if __name__ == "__main__":
    main()

